import React, { useEffect, useState } from 'react'
import {
  CAvatar,
  CBadge,
  CButton,
  CCollapse,
  CSmartTable,
} from '@coreui/react-pro'

const getBadge = (status) => {
  switch (status) {
    case 'Active':
      return 'success'
    case 'Inactive':
      return 'secondary'
    case 'Pending':
      return 'warning'
    case 'Banned':
      return 'danger'
    default:
      return 'primary'
  }
}

const Colleges = () => {
  useEffect(() => {
    window.scrollTo(0, 0)
  }, [])

  const [details, setDetails] = useState([])

  const toggleDetails = (id) => {
    setDetails((prev) =>
      prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]
    )
  }

  const columns = [
    { key: 'avatar', label: '', filter: false, sorter: false },
    { key: 'name', label: 'Name', _style: { width: '20%' } },
    { key: 'registered', label: 'Registered On' },
    { key: 'role', label: 'Role', _style: { width: '20%' } },
    { key: 'status', label: 'Status' },
    {
      key: 'show_details',
      label: 'Actions',
      _style: { width: '1%' },
      filter: false,
      sorter: false,
    },
  ]

  const items = [
    {
      id: 1,
      name: 'Samppa Nori',
      avatar: '1.jpg',
      registered: '2021/03/01',
      role: 'Member',
      status: 'Active',
    },
    {
      id: 2,
      name: 'Estavan Lykos',
      avatar: '2.jpg',
      registered: '2018/02/07',
      role: 'Staff',
      status: 'Inactive',
    },
    {
      id: 3,
      name: 'Chetan Mohamed',
      avatar: '3.jpg',
      registered: '2020/01/15',
      role: 'Admin',
      status: 'Pending',
    },
    // ... other items (same as before)
  ]

  return (
    <div className="p-4">
      <h3 className="mb-4 fw-bold text-primary">Colleges</h3>

      <CSmartTable
        columns={columns}
        items={items}
        columnFilter
        columnSorter
        footer
        pagination
        itemsPerPage={5}
        itemsPerPageSelect
        clickableRows
        tableFilter
        cleaner
        selectable
        activePage={1}
        sorterValue={{ column: 'status', state: 'asc' }}
        tableProps={{
          className: 'align-middle border shadow-sm rounded overflow-hidden',
          striped: true,
          hover: true,
          responsive: true,
        }}
        tableBodyProps={{
          className: 'align-middle',
        }}
        scopedColumns={{
          avatar: (item) => (
            <td>
              <CAvatar
                src={`../../images/avatars/${item.avatar}`}
                size="md"
                className="border shadow-sm"
              />
            </td>
          ),
          registered: (item) => {
            const date = new Date(item.registered)
            return (
              <td>
                {date.toLocaleDateString('en-US', {
                  year: 'numeric',
                  month: 'short',
                  day: 'numeric',
                })}
              </td>
            )
          },
          status: (item) => (
            <td>
              <CBadge className="px-3 py-1 text-uppercase" color={getBadge(item.status)}>
                {item.status}
              </CBadge>
            </td>
          ),
          show_details: (item) => (
            <td className="text-end">
              <CButton
                color="info"
                variant="ghost"
                size="sm"
                onClick={() => toggleDetails(item.id)}
              >
                {details.includes(item.id) ? 'Hide' : 'Details'}
              </CButton>
            </td>
          ),
          details: (item) => (
            <td colSpan={6}>
              <CCollapse visible={details.includes(item.id)}>
                <div className="p-4 bg-light rounded border mt-2">
                  <h5 className="mb-2 text-dark">{item.name}</h5>
                  <p className="text-muted mb-2">
                    Role: <strong>{item.role}</strong> <br />
                    Registered on:{' '}
                    {new Date(item.registered).toLocaleDateString('en-US')}
                  </p>
                  <div>
                    <CButton size="sm" color="primary" className="me-2">
                      Edit
                    </CButton>
                    <CButton size="sm" color="danger">
                      Delete
                    </CButton>
                  </div>
                </div>
              </CCollapse>
            </td>
          ),
        }}
      />
    </div>
  )
}

export default Colleges
